    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

const boilerplate = [
  /CONFIDENTIALITY NOTICE[\s\S]*?$/i,
  /This email and any attachments[\s\S]*?$/i,
  /DISCLAIMER[\s\S]*?$/i,
  /Sent from my iPhone/i,
  /Get Outlook for/i
];
for (const p of boilerplate) { text = text.replace(p, ''); }

return [{ json: { ...emailData, extracted_text: text.trim(), extraction_method: 'email_body' } }];

// Parse thread: split a forwarded/reply email thread into individual messages.
// Each message gets its own sender, date, and body — so Qdrant gets accurate timestamps.
// Falls back to treating the whole body as a single message if no thread structure detected.

const data = $input.first().json;
const rawText = data.extracted_text || data.text || '';

// --- Thread splitter patterns (Gmail, Outlook, Apple Mail) ---
// Pattern 1: Gmail forwarded message header
//   ---------- Forwarded message ---------
//   From: Name <email>
//   Date: Wed, Jan 21, 2026 at 5:50 PM
const GMAIL_FWD = /^-{5,}\s*Forwarded message\s*-{5,}\s*$/im;

// Pattern 2: Gmail/Outlook reply quote header
//   On Wed, Jan 21, 2026 at 5:50 PM Austin Holland <austin@...> wrote:
const REPLY_HEADER = /^On\s+\w{3},?\s+\w+\s+\d+,\s+\d{4}\s+at\s+[\d:]+\s*(AM|PM).*wrote:\s*$/im;

// Pattern 3: Outlook forwarded block
//   From: Name <email>
//   Sent: Wednesday, January 21, 2026 5:50 PM
//   To: ...
//   Subject: ...
const OUTLOOK_FWD = /^From:\s*.+\r?\nSent:\s*.+\r?\nTo:\s*/im;

// Helper: extract From/Date from a header block
function parseHeaders(block) {
  const fromMatch = block.match(/From:\s*([^\n\r]+)/i);
  const dateMatch = block.match(/(?:Date|Sent):\s*([^\n\r]+)/i);
  const fromRaw = fromMatch ? fromMatch[1].trim() : '';
  const dateRaw = dateMatch ? dateMatch[1].trim() : '';

  // Extract email address from 'Name <email>' or bare email
  const emailMatch = fromRaw.match(/<([^>]+)>/) || fromRaw.match(/(\S+@\S+)/);
  const senderEmail = emailMatch ? emailMatch[1] : fromRaw;

  // Parse date — JS Date handles most formats gracefully
  let dateCreated = data.email_date || new Date().toISOString();
  if (dateRaw) {
    const parsed = new Date(dateRaw);
    if (!isNaN(parsed.getTime())) dateCreated = parsed.toISOString();
  }

  return { senderEmail, dateCreated };
}

// --- Split logic ---
let messages = [];

// Try to split on Gmail forwarded header
if (GMAIL_FWD.test(rawText)) {
  const parts = rawText.split(GMAIL_FWD);
  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) continue;
    const { senderEmail, dateCreated } = parseHeaders(trimmed);
    // Strip the header lines, keep the body
    const body = trimmed.replace(/^(From:|Date:|To:|Cc:|Subject:)[^\n]*\n/gim, '').trim();
    if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
  }
}

// Try reply-quote headers if no forwarded splits found
if (messages.length <= 1) {
  const parts = rawText.split(REPLY_HEADER);
  if (parts.length > 1) {
    messages = [];
    for (const part of parts) {
      const trimmed = part.trim();
      if (!trimmed) continue;
      // Reply headers appear as separators — try to parse date from preceding line
      const { senderEmail, dateCreated } = parseHeaders(trimmed);
      const body = trimmed.replace(/^On\s+[^\n]+wrote:/im, '').trim();
      if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
    }
  }
}

// Try Outlook forwarded block
if (messages.length <= 1 && OUTLOOK_FWD.test(rawText)) {
  const parts = rawText.split(/(?=^From:\s*.+\r?\nSent:\s*)/im);
  if (parts.length > 1) {
    messages = [];
    for (const part of parts) {
      const trimmed = part.trim();
      if (!trimmed) continue;
      const { senderEmail, dateCreated } = parseHeaders(trimmed);
      const body = trimmed.replace(/^(From:|Sent:|To:|Cc:|Subject:)[^\n]*\n/gim, '').trim();
      if (body.length > 50) messages.push({ senderEmail, dateCreated, body });
    }
  }
}

// Fallback: single message, no thread detected
if (messages.length === 0) {
  messages = [{ senderEmail: data.sender_email || '', dateCreated: data.email_date || new Date().toISOString(), body: rawText }];
}

// Sort chronologically (oldest first)
messages.sort((a, b) => new Date(a.dateCreated) - new Date(b.dateCreated));

// Return one item per message, carrying all deal metadata but overriding sender/date per message
return messages.map((msg, i) => ({
  json: {
    ...data,
    extracted_text: msg.body,
    sender_email: msg.senderEmail || data.sender_email,
    email_date: msg.dateCreated,
    thread_index: i,
    thread_total: messages.length,
    // Preserve original message_id but make each thread message unique for dedup
    message_id: messages.length > 1 ? `${data.message_id}_t${i}` : data.message_id
  }
}));

// Normalize extracted text from different extraction nodes into a single text field.
// ReadPdf outputs json.text
// PPTX Code node outputs json.extracted_text
// SpreadsheetFile outputs rows as separate items — need concatenation into single item
// Unknown attachments pass through with existing text

// Helper: resolve correct metadata source for the current processing path.
// The Extract from File (XLSX/CSV) nodes strip input json and replace with row data,
// so we must look upstream at the Decode nodes (which still hold metadata).
// The Decode nodes only ran for their specific path, so we try each in order.
function resolveMetadata() {
  const metaKeys = [
    'message_id', 'doc_type', 'deal_id', 'company_name', 'sender_email',
    'sender_domain', 'subject', 'date_created', 'attribution_confidence',
    'reasoning', 'deal_stage', 'attachment_name', 'attachment_type',
    'qdrant_namespace', 'snippet'
  ];

  // Try upstream Decode nodes first — they have path-specific metadata
  const decodeSources = [
    'Code: Decode XLSX Binary',
    'Code: Decode Spreadsheet Binary',
    'Code: Decode PDF Binary'
  ];

  for (const nodeName of decodeSources) {
    try {
      const srcData = $(nodeName).first().json;
      if (srcData && srcData.message_id) {
        const meta = {};
        for (const k of metaKeys) {
          if (srcData[k] !== undefined && srcData[k] !== null) {
            meta[k] = srcData[k];
          }
        }
        return meta;
      }
    } catch(e) {
      // Node didn't run on this path — expected, continue
    }
  }

  // Fallback: Split node. Try to find the correct item by doc_type matching.
  try {
    const splitItems = $('Code: Split Body + Attachments').all();
    // If there's only one split item, use it
    if (splitItems.length === 1) {
      const srcData = splitItems[0].json;
      const meta = {};
      for (const k of metaKeys) {
        if (srcData[k] !== undefined && srcData[k] !== null) {
          meta[k] = srcData[k];
        }
      }
      return meta;
    }
    // Multiple split items: prefer attachment types over email_body
    const attachmentItem = splitItems.find(item =>
      item.json.doc_type && item.json.doc_type !== 'email_body'
    );
    if (attachmentItem) {
      const srcData = attachmentItem.json;
      const meta = {};
      for (const k of metaKeys) {
        if (srcData[k] !== undefined && srcData[k] !== null) {
          meta[k] = srcData[k];
        }
      }
      return meta;
    }
    // Last resort: first item
    const srcData = splitItems[0].json;
    const meta = {};
    for (const k of metaKeys) {
      if (srcData[k] !== undefined && srcData[k] !== null) {
        meta[k] = srcData[k];
      }
    }
    return meta;
  } catch(e) {
    return {};
  }
}

const items = $input.all();

// Detect multi-row case: multiple items where none have message_id (spreadsheet rows lose metadata)
const hasMetadata = items.some(item => item.json.message_id);
const isMultiRowNoMeta = items.length > 1 && !hasMetadata;

if (isMultiRowNoMeta) {
  // CSV/XLSX case: aggregate all rows into one text blob, pull metadata from upstream
  const metadata = resolveMetadata();

  // Build CSV text: header row + data rows
  const allKeys = new Set();
  for (const item of items) {
    for (const k of Object.keys(item.json)) {
      if (k !== 'attachment_contentBytes' && k !== 'outlookAttachments') {
        allKeys.add(k);
      }
    }
  }
  const headers = Array.from(allKeys);
  const lines = [headers.join(' | ')];
  for (const item of items) {
    const vals = headers.map(h => String(item.json[h] || ''));
    lines.push(vals.join(' | '));
  }
  const extractedText = lines.join('\n');

  return [{
    json: {
      ...metadata,
      doc_type: metadata.doc_type || 'csv_attachment',
      text: extractedText,
      extracted_text: extractedText
    }
  }];
}

// Non-multi-row case: process each item individually
const results = [];

for (const item of items) {
  const data = item.json;

  // If this item is missing message_id, try to recover metadata from upstream
  let baseData = data;
  if (!data.message_id) {
    const recovered = resolveMetadata();
    baseData = { ...recovered, ...data };
  }

  // Try known text fields in priority order
  let extractedText = data.extracted_text || data.text || '';

  // SpreadsheetFile single-row fallback: concatenate all non-meta fields
  if (!extractedText && typeof data === 'object') {
    const keys = Object.keys(data).filter(k =>
      k !== 'attachment_contentBytes' && k !== 'outlookAttachments' &&
      k !== 'doc_type' && k !== 'deal_id' && k !== 'company_name' &&
      k !== 'sender_email' && k !== 'sender_domain' && k !== 'subject' &&
      k !== 'message_id' && k !== 'date_created' && k !== 'attribution_confidence' &&
      k !== 'reasoning' && k !== 'deal_stage' && k !== 'attachment_name' &&
      k !== 'attachment_type' && k !== 'qdrant_namespace' && k !== 'snippet'
    );
    if (keys.length > 0) {
      const rowParts = keys.map(k => k + ': ' + String(data[k] || ''));
      extractedText = rowParts.join(' | ');
    }
  }

  if (!extractedText || extractedText.length < 10) {
    extractedText = '[No text extracted from attachment]';
  }

  // Build clean output — strip binary/large fields
  const cleanMeta = {};
  for (const key of Object.keys(baseData)) {
    if (key !== 'attachment_contentBytes' && key !== 'outlookAttachments') {
      cleanMeta[key] = baseData[key];
    }
  }

  results.push({
    json: {
      ...cleanMeta,
      text: extractedText,
      extracted_text: extractedText
    }
  });
}

return results;

// Contextual enrichment: prepend deal/doc context to extracted text
const data = $input.first().json;

// For calendar invites, embeddable_text is already built by Code: Parse ICS
if (data.doc_type === 'calendar_invite' && data.embeddable_text) {
  return [{ json: { ...data, enriched_text: data.embeddable_text, extracted_text: data.embeddable_text } }];
}

const dealId = data.deal_id || 'unknown';
const companyName = data.company_name || data.guessed_deal_company || 'Unknown Company';
const docType = data.doc_type || 'email';
const senderEmail = data.sender_email || '';
const rawText = data.extracted_text || '';

// For call transcripts, try to extract the actual call date from the document content.
// Transcripts are often forwarded days after the call occurred, so the Gmail Date header
// reflects when the email was sent, not when the call happened.
// Look for common transcript date patterns at the top of the document.
function extractTranscriptDate(text) {
  // Match patterns like:
  //   Date: January 21, 2026
  //   Date: 2026-01-21
  //   Call Date: Wed, Jan 21, 2026
  //   January 21, 2026  (standalone line near top)
  const patterns = [
    /^(?:call\s+)?date[:\s]+([\w,\s]+\d{4})/im,
    /^date[:\s]+(\d{4}-\d{2}-\d{2})/im,
    /^(?:meeting|session|call)[\s\S]{0,40}?(\b(?:january|february|march|april|may|june|july|august|september|october|november|december)\s+\d{1,2},?\s+\d{4})/im,
    /\b(\d{4}-\d{2}-\d{2})\b/,
    /\b((?:january|february|march|april|may|june|july|august|september|october|november|december)\s+\d{1,2},?\s+\d{4})\b/i
  ];
  // Only scan the first 500 chars — date lines are always near the top
  const sample = text.slice(0, 500);
  for (const pattern of patterns) {
    const match = sample.match(pattern);
    if (match) {
      const parsed = new Date(match[1]);
      if (!isNaN(parsed.getTime())) return parsed.toISOString();
    }
  }
  return null;
}

let resolvedDate = data.email_date;
if (docType === 'call_transcript') {
  const transcriptDate = extractTranscriptDate(rawText);
  if (transcriptDate) resolvedDate = transcriptDate;
}

const emailDate = resolvedDate ? new Date(resolvedDate).toISOString().split('T')[0] : new Date().toISOString().split('T')[0];

const contextHeader = `[DEAL CONTEXT]\nDeal: ${companyName} (ID: ${dealId})\nDocument Type: ${docType}\nDate: ${emailDate}\nSource: ${senderEmail}\n[END CONTEXT]\n\n`;

const enrichedText = contextHeader + rawText;

return [{ json: { ...data, enriched_text: enrichedText, email_date: resolvedDate || data.email_date } }];

// Split enriched text into chunks, carrying all deal metadata forward.
// call_transcript: sentence-boundary aware, chunkSize=2500, overlap=250
//   — keeps full speaker utterances intact so CAS-scoring evidence
//     (e.g. "I would stagegate this...") never splits across chunks.
// All other doc types: fixed character split, chunkSize=1800, overlap=180
const data = $input.first().json;
const text = data.enriched_text || '';
const isTranscript = (data.doc_type === 'call_transcript');
const isAttachment = ['pdf_attachment','pptx_attachment','csv_attachment'].includes(data.doc_type);
const chunkSize    = (isTranscript || isAttachment) ? 2500 : 1800;
const chunkOverlap = (isTranscript || isAttachment) ? 250  : 180;

let chunks = [];

if (isTranscript) {
  // Sentence-boundary aware splitting for transcripts.
  // Split on sentence-ending punctuation OR speaker-turn boundaries ("Name: ").
  // Regex: split AFTER . ? ! followed by whitespace+capital, OR at a newline
  // followed by a word and colon (speaker label like "Austin:" or "Brad:").
  const sentenceBreak = /(?<=[.?!])\s+(?=[A-Z])|(?=\n[A-Za-z][^:\n]{0,30}:)/g;
  const sentences = text.split(sentenceBreak).filter(s => s.trim().length > 0);

  let current = '';
  for (const sentence of sentences) {
    if (current.length + sentence.length > chunkSize && current.length > 0) {
      chunks.push(current.trim());
      // Overlap: keep the tail of the current chunk as the start of the next
      const overlapStart = current.length > chunkOverlap
        ? current.length - chunkOverlap
        : 0;
      current = current.slice(overlapStart) + ' ' + sentence;
    } else {
      current += (current.length > 0 ? ' ' : '') + sentence;
    }
  }
  if (current.trim().length > 0) chunks.push(current.trim());

} else {
  // Fixed character split for emails, PDFs, and everything else
  let start = 0;
  while (start < text.length) {
    const end = Math.min(start + chunkSize, text.length);
    chunks.push(text.slice(start, end));
    if (end === text.length) break;
    start = end - chunkOverlap;
  }
}

return chunks.map((chunk, index) => ({
  json: {
    ...data,
    chunk_text: chunk,
    chunk_index: index,
    total_chunks: chunks.length
  }
}));

// Build Qdrant point with embedding + full metadata payload
// HTTP Request nodes break paired item chains in n8n — retrieve chunk data
// by matching on chunk_index from all Code: Chunk Text outputs.
const allItems = $input.all();
const allChunks = $('Code: Chunk Text').all();

// UUID v4 without require('crypto') — n8n sandbox blocks it
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

// Build one point per item in input (each is one OpenAI embed response)
return allItems.map((item, i) => {
  const embedding = item.json.data?.[0]?.embedding;
  if (!embedding) throw new Error(`No embedding at index ${i}`);
  // Match chunk by index — allChunks and allItems are in the same order
  const chunkData = (allChunks[i] || allChunks[0]).json;
  const point = {
    id: uuidv4(),
    vector: embedding,
    payload: {
      deal_id: chunkData.deal_id || 'unknown',
      company_name: chunkData.company_name || chunkData.guessed_deal_company || 'Unknown',
      doc_type: chunkData.doc_type || 'email_body',
      sender_domain: chunkData.sender_domain || '',
      attribution_confidence: chunkData.attribution_confidence || 'low',
      date_created: chunkData.email_date || '',
      message_id: chunkData.message_id || '',
      chunk_index: chunkData.chunk_index || i,
      page_content: chunkData.chunk_text || ''
    }
  };
  return { json: { point, ...chunkData } };
});

// Pull deal metadata from the attribution node (Postgres: Upsert Deal outputs {success:true})
// Use Code: Assign Deal ID as the source of truth for deal metadata
let dealData;
try {
  dealData = $('Code: Assign Deal ID').first().json;
} catch(e) {
  dealData = $('Code: Assign Unattributed Deal ID').first().json;
}
return [{ json: dealData }];

// Count how many chunks were upserted into Qdrant.
// Also builds the escaped SQL INSERT for Postgres: Log Ingestion.
// For attachment items (pdf_attachment, pptx_attachment, csv_attachment),
// appends _att_<index> to message_id so each gets its own ingestion_log entry.
const enrichData = $input.first().json;
const chunkCount = enrichData.total_chunks || $input.all().length;

// sq() escapes single quotes for SQL: ' -> ''  then wraps in single quotes
function sq(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

// For attachments, create a unique message_id by appending attachment name hash
let messageId = enrichData.message_id;
const attachmentTypes = ['pdf_attachment', 'pptx_attachment', 'csv_attachment', 'xlsx_attachment'];
if (attachmentTypes.includes(enrichData.doc_type) && enrichData.attachment_name) {
  // Create a short hash from the attachment name for uniqueness
  const attName = enrichData.attachment_name.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 40);
  messageId = messageId + '_att_' + attName;
}

const query = `INSERT INTO ingestion_log (message_id, deal_id, attribution_confidence, attribution_status, sender_email, sender_domain, subject, doc_type, attachment_count, chunk_count, qdrant_namespace, classification_reasoning) VALUES (${sq(messageId)}, ${sq(enrichData.deal_id)}, ${sq(enrichData.attribution_confidence)}, 'processed', ${sq(enrichData.sender_email)}, ${sq(enrichData.sender_domain)}, ${sq(enrichData.subject)}, ${sq(enrichData.doc_type)}, 0, ${chunkCount}, ${sq(enrichData.qdrant_namespace)}, ${sq(enrichData.reasoning)}) ON CONFLICT (message_id) DO NOTHING`;

return [{ json: { ...enrichData, chunk_count: chunkCount, query } }];

// Normalise email fields for content-level dedup
// Strips FW:/Re:/Fwd: prefix from subject so forwarded copies are caught
const msg = $input.first().json;

function getHeader(headers, name) {
  if (!headers) return '';
  const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
  return h ? h.value : '';
}
const headers = msg.payload?.headers || [];
const rawSubject = msg.Subject || msg.subject || getHeader(headers, 'Subject') || '';
const rawFrom    = msg.From    || msg.from    || getHeader(headers, 'From')    || '';

// Strip reply/forward prefixes recursively
const normSubject = rawSubject.replace(/^(fw:|re:|fwd:|forward:)\s*/gi, '').trim().toLowerCase();

// Extract domain from From header  'Name <email@domain.com>' or 'email@domain.com'
const addrMatch = rawFrom.match(/<([^>]+)>/) || rawFrom.match(/(\S+@\S+)/);
const senderAddr = addrMatch ? addrMatch[1] : rawFrom;
const domain = senderAddr.includes('@') ? senderAddr.split('@')[1].toLowerCase().replace(/['>]/g,'') : '';

return [{ json: { ...msg, norm_subject: normSubject, sender_domain_dedup: domain } }];

// Normalize Power Automate Outlook payload to match Gmail field shape
// Expected PA payload:
// { messageId, subject, from, to, sentAt, bodyContent, attachments: [{name, contentType, contentBytes}] }
const body = $input.first().json.body || $input.first().json;

const messageId   = String(body.messageId || body.message_id || '');
const subject     = body.subject || '';
const from        = body.from || '';
const to          = body.to || '';
const sentAt      = body.sentAt || body.sent_at || new Date().toISOString();
const rawText     = body.bodyContent || body.body_content || '';
const attachments = body.attachments || [];

// Strip HTML tags and decode common HTML entities to get clean plain text
function stripHtml(html) {
  if (!html || !html.includes('<')) return html;
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const text = stripHtml(rawText);

return [{
  json: {
    id: messageId,
    Subject: subject,
    From: from,
    To: to,
    Date: sentAt,
    text: text,
    snippet: text.substring(0, 200),
    outlookAttachments: attachments,
    source: 'outlook'
  }
}];

const d = $('Code: Normalize For Dedup').first().json;
const from = d.From || d.from || 'unknown';
const subject = d.Subject || d.subject || '(no subject)';
const bodyText = (d.text ?? d.snippet ?? '').slice(0, 2000);

// Build past corrections section from recent feedback
let correctionsSection = '';
try {
  const correctionRows = $('Postgres: Get Recent Corrections').all();
  if (correctionRows && correctionRows.length > 0) {
    const examples = correctionRows
      .map(r => r.json)
      .filter(r => r.classification_feedback || r.doc_type_override || r.deal_id_override)
      .map(r => {
        const parts = [];
        parts.push(`Email from domain "${r.sender_domain || 'unknown'}" with subject "${r.subject || '(no subject)'}"`);
        parts.push(`was classified as ${r.doc_type} for deal ${r.deal_id}.`);
        const feedback = r.classification_feedback || '';
        if (r.doc_type_override && r.doc_type_override !== r.doc_type) {
          parts.push(`Austin corrected doc_type to "${r.doc_type_override}".`);
        }
        if (r.deal_id_override && r.deal_id_override !== r.deal_id) {
          parts.push(`Austin corrected deal to "${r.deal_id_override}".`);
        }
        if (feedback) {
          parts.push(`Feedback: "${feedback}"`);
        }
        return '- ' + parts.join(' ');
      });
    if (examples.length > 0) {
      correctionsSection = '\n\nPAST CORRECTIONS (learn from these — avoid repeating these mistakes):\n' + examples.join('\n');
    }
  }
} catch (e) {
  // No corrections available — continue without them
}

const prompt = `You are a deal attribution classifier for Clearwater Security & Compliance. Analyze this email and return ONLY a JSON object (no markdown, no code fences) with these exact fields:
{
  "company_name": "<company name or Unknown>",
  "sender_domain": "<domain from sender email>",
  "doc_type": "<email_body|call_transcript|pdf_attachment|pptx_attachment|csv_attachment|calendar_invite|other>",
  "deal_indicators": [],
  "guessed_deal_company": "<company name>",
  "confidence": "<high|medium|low>",
  "confidence_score": 0.0,
  "reasoning": "<one sentence>"
}

CLASSIFICATION RULES (apply in order):

RULE 1 - doc_type from subject line (overrides body inference):
If the subject contains "transcript", "call transcript", "recording", or "call notes" set doc_type to call_transcript, regardless of sender or body content.
If the subject contains "calendar invite" or the body contains BEGIN:VCALENDAR/DTSTART/DTEND set doc_type to calendar_invite.

RULE 2 - company attribution when sender is internal (clearwatersecurity.com):
If the sender domain is clearwatersecurity.com, do NOT use the sender to identify the deal company.
Extract the prospect company name from the subject line (e.g. "Velentium" from "FW: Call Transcript - Velentium | Clearwater").
Set guessed_deal_company to that company name and confidence to high if a company name is clearly present in the subject.
If no company name can be extracted from the subject, set confidence to low.

RULE 3 - company attribution when sender is external:
