// Split an email into multiple items: one for the body text, one per processable attachment.
// This ensures emails with body text AND attachments get BOTH processed.
// Checks multiple field locations for attachments (PA webhook format varies).
const data = $input.first().json;

// Get the original classified doc_type (email_body, call_transcript, etc.)
const originalDocType = data.doc_type;

// Gather attachments from ALL possible locations
let attachments = [];

// 1. Try upstream Normalize node (canonical location)
try {
  const normData = $('Code: Normalize Outlook Payload').first().json;
  if (Array.isArray(normData.outlookAttachments) && normData.outlookAttachments.length > 0) {
    attachments = normData.outlookAttachments;
  } else if (Array.isArray(normData.attachments) && normData.attachments.length > 0) {
    attachments = normData.attachments;
  }
} catch(e) {
  // Node reference not available — fall through
}

// 2. If still empty, check current data object (may have been renamed by Parse Classification)
if (attachments.length === 0) {
  if (Array.isArray(data.outlookAttachments) && data.outlookAttachments.length > 0) {
    attachments = data.outlookAttachments;
  } else if (Array.isArray(data.attachments) && data.attachments.length > 0) {
    attachments = data.attachments;
  }
}

// 3. Last resort: check raw webhook body
if (attachments.length === 0) {
  try {
    const webhookData = $('Webhook: Receive Outlook Email').first().json;
    const body = webhookData.body || webhookData;
    if (Array.isArray(body.attachments) && body.attachments.length > 0) {
      attachments = body.attachments;
    }
  } catch(e) {
    // Webhook node reference not available
  }
}

// Extension to doc_type mapping
const extMap = {
  '.pdf': 'pdf_attachment',
  '.pptx': 'pptx_attachment',
  '.ppt': 'pptx_attachment',
  '.csv': 'csv_attachment',
  '.xlsx': 'xlsx_attachment',
  '.xls': 'xlsx_attachment'
};

// Filter to non-inline, processable attachments
const processableAttachments = attachments.filter(att => {
  if (!att || typeof att !== 'object') return false;
  if (att.isInline === true) return false;
  const name = (att.name || att.Name || '').toLowerCase();
  return Object.keys(extMap).some(ext => name.endsWith(ext));
});

// Build output items
const outputItems = [];

// 1. Always output the original body item (email_body or call_transcript)
//    Only include if the doc_type is a body type (not already an attachment type)
const bodyTypes = ['email_body', 'call_transcript', 'calendar_invite'];
if (bodyTypes.includes(originalDocType)) {
  outputItems.push({
    json: {
      ...data,
      doc_type: originalDocType,
      attachment_name: null,
      attachment_contentType: null,
      attachment_contentBytes: null
    }
  });
}

// 2. One item per processable attachment
for (const att of processableAttachments) {
  const name = (att.name || att.Name || '').toLowerCase();
  const ext = Object.keys(extMap).find(e => name.endsWith(e));
  if (ext) {
    outputItems.push({
      json: {
        ...data,
        doc_type: extMap[ext],
        attachment_name: att.name || att.Name || '',
        attachment_contentType: att.contentType || att.ContentType || '',
        attachment_contentBytes: att.contentBytes || att.ContentBytes || ''
      }
    });
  }
}

// If somehow we have no items (e.g. doc_type was pdf_attachment with no actual attachments),
// fall through with original data
if (outputItems.length === 0) {
  outputItems.push({
    json: {
      ...data,
      attachment_name: null,
      attachment_contentType: null,
      attachment_contentBytes: null
    }
  });
}

return outputItems;

// Decode base64 PDF attachment and output as n8n binary for ReadPdf node.
// Input: items with attachment_contentBytes (base64 string)
// Output: { json: { ...metadata }, binary: { data: binaryData } }
// Guard: if contentBytes is empty after all fallbacks, skip with error message
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let base64Content = data.attachment_contentBytes || '';
  let attachmentName = data.attachment_name || 'attachment.pdf';

  // Build clean metadata (exclude raw binary content to save memory)
  const metadata = {};
  for (const key of Object.keys(data)) {
    if (key !== 'attachment_contentBytes' && key !== 'outlookAttachments') {
      metadata[key] = data[key];
    }
  }

  if (!base64Content) {
    // Fallback: legacy outlookAttachments lookup
    const attachments = data.outlookAttachments || [];
    const pdfAttachment = attachments.find(a => {
      const name = (a.name || '').toLowerCase();
      const ct = (a.contentType || '').toLowerCase();
      return ct.includes('pdf') || name.endsWith('.pdf');
    });
    if (pdfAttachment) {
      base64Content = pdfAttachment.contentBytes || '';
      attachmentName = pdfAttachment.name || 'attachment.pdf';
    }
  }

  // Guard: if still no content, skip with descriptive error — do NOT crash
  if (!base64Content) {
    const skipMsg = 'PDF attachment "' + attachmentName + '" has empty contentBytes. ' +
      'The attachment may have been filtered by Power Automate or sent inline. ' +
      'message_id: ' + (metadata.message_id || 'unknown');
    results.push({
      json: {
        ...metadata,
        text: '[SKIPPED: ' + skipMsg + ']',
        extracted_text: '[SKIPPED: ' + skipMsg + ']',
        doc_type: 'pdf_attachment',
        _skipped: true,
        _skip_reason: skipMsg
      }
    });
    continue;
  }

  const buffer = Buffer.from(base64Content, 'base64');
  const binaryData = await this.helpers.prepareBinaryData(
    buffer,
    attachmentName,
    'application/pdf'
  );

  results.push({
    json: { ...metadata, attachment_name: attachmentName, doc_type: 'pdf_attachment' },
    binary: { data: binaryData }
  });
}

return results;

// Extract text from PPTX attachment using adm-zip.
// Decodes base64 → Buffer → AdmZip → extracts slide XML → strips tags.
// Single node — no binary output needed, does both decode and extract.
const AdmZip = require('adm-zip');
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let base64Content = data.attachment_contentBytes || '';
  let attachmentName = data.attachment_name || 'attachment.pptx';

  // Build clean metadata (exclude raw binary content)
  const metadata = {};
  for (const key of Object.keys(data)) {
    if (key !== 'attachment_contentBytes' && key !== 'outlookAttachments') {
      metadata[key] = data[key];
    }
  }

  if (!base64Content) {
    // Fallback: legacy outlookAttachments lookup
    const attachments = data.outlookAttachments || [];
    const pptxAttachment = attachments.find(a => {
      const name = (a.name || '').toLowerCase();
      const ct = (a.contentType || '').toLowerCase();
      return ct.includes('presentation') || ct.includes('pptx') || name.endsWith('.pptx') || name.endsWith('.ppt');
    });
    if (!pptxAttachment) {
      results.push({ json: { ...metadata, extracted_text: '[No PPTX attachment found]' } });
      continue;
    }
    base64Content = pptxAttachment.contentBytes;
    attachmentName = pptxAttachment.name || 'attachment.pptx';
  }

  const buffer = Buffer.from(base64Content, 'base64');
  const zip = new AdmZip(buffer);
  const entries = zip.getEntries();

  // Get slide XMLs sorted by slide number
  const slideEntries = entries
    .filter(e => /^ppt\/slides\/slide\d+\.xml$/i.test(e.entryName))
    .sort((a, b) => {
      const numA = parseInt(a.entryName.match(/slide(\d+)/i)[1]);
      const numB = parseInt(b.entryName.match(/slide(\d+)/i)[1]);
      return numA - numB;
    });

  let fullText = '';
  for (const entry of slideEntries) {
    const xml = entry.getData().toString('utf8');
    const slideNum = entry.entryName.match(/slide(\d+)/i)[1];
    // Strip XML tags, decode entities
    const text = xml
      .replace(/<a:br[^/]*\/>/gi, '\n')
      .replace(/<\/a:p>/gi, '\n')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&apos;/g, "'")
      .replace(/&#\d+;/g, '')
      .replace(/ {2,}/g, ' ')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
    if (text) {
      fullText += '\n--- Slide ' + slideNum + ' ---\n' + text + '\n';
    }
  }

  if (!fullText.trim()) {
    fullText = '[PPTX contained no extractable text]';
  }

  results.push({ json: { ...metadata, extracted_text: fullText.trim(), attachment_name: attachmentName } });
}

return results;

// Decode base64 CSV/XLSX attachment and output as n8n binary for SpreadsheetFile node.
// Input: items with attachment_contentBytes (base64 string)
// Output: { json: { ...metadata }, binary: { data: binaryData } }
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  let base64Content = data.attachment_contentBytes || '';
  let attachmentName = data.attachment_name || 'attachment.csv';

  // Build clean metadata (exclude raw binary content to save memory)
  const metadata = {};
  for (const key of Object.keys(data)) {
    if (key !== 'attachment_contentBytes' && key !== 'outlookAttachments') {
      metadata[key] = data[key];
    }
  }

  if (!base64Content) {
    // Fallback: legacy outlookAttachments lookup
    const attachments = data.outlookAttachments || [];
    const csvAttachment = attachments.find(a => {
      const name = (a.name || '').toLowerCase();
      const ct = (a.contentType || '').toLowerCase();
      return ct.includes('csv') || ct.includes('comma-separated') || ct.includes('csv') || ct.includes('comma-separated') || name.endsWith('.csv');
    });
    if (!csvAttachment) {
      results.push({ json: { ...metadata, text: '[No spreadsheet attachment found]', doc_type: 'csv_attachment' } });
      continue;
    }
    base64Content = csvAttachment.contentBytes;
    attachmentName = csvAttachment.name || 'attachment.csv';
  }

  const buffer = Buffer.from(base64Content, 'base64');
  const ext = attachmentName.toLowerCase().split('.').pop();
  let mimeType = 'text/csv';
  if (ext === 'xlsx') {
    mimeType = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
  } else if (ext === 'xls') {
    mimeType = 'application/vnd.ms-excel';
  }

  const binaryData = await this.helpers.prepareBinaryData(
    buffer,
    attachmentName,
    mimeType
  );

  results.push({
    json: { ...metadata, attachment_name: attachmentName, doc_type: 'csv_attachment' },
    binary: { data: binaryData }
  });
}

return results;

